/**
 * API client for communicating with the backend solver
 */

import type { SolverInput, SolverOutput } from "@uptime/types";

const API_BASE = "/api";

export interface ApiError {
  message: string;
  status: number;
}

export async function solveSchedule(input: SolverInput): Promise<SolverOutput> {
  const response = await fetch(`${API_BASE}/solver/solve`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(input),
  });

  if (!response.ok) {
    const error = await response.json().catch(() => ({ message: "Unknown error" }));
    throw new Error(error.message || `HTTP ${response.status}`);
  }

  return response.json();
}

export async function checkSolverHealth(): Promise<{ status: string; solver: string }> {
  const response = await fetch(`${API_BASE}/solver/health`);

  if (!response.ok) {
    throw new Error(`Solver unavailable: HTTP ${response.status}`);
  }

  return response.json();
}

