/**
 * Solver API Routes
 */

import { Hono } from "hono";
import { zValidator } from "@hono/zod-validator";
import { z } from "zod";
import { createSolverAdapter } from "../adapter/solver-adapter";
import type { SolverInput } from "@uptime/types";

const solver = new Hono();

/** Rate limiter: track requests per IP (simple in-memory implementation) */
const rateLimiter = new Map<string, { count: number; resetTime: number }>();
const RATE_LIMIT = 10; // requests per window
const RATE_WINDOW_MS = 60_000; // 1 minute

function checkRateLimit(ip: string): boolean {
  const now = Date.now();
  const entry = rateLimiter.get(ip);

  if (!entry || now > entry.resetTime) {
    rateLimiter.set(ip, { count: 1, resetTime: now + RATE_WINDOW_MS });
    return true;
  }

  if (entry.count >= RATE_LIMIT) {
    return false;
  }

  entry.count++;
  return true;
}

// Clean up old rate limit entries periodically
setInterval(() => {
  const now = Date.now();
  for (const [ip, entry] of rateLimiter.entries()) {
    if (now > entry.resetTime) {
      rateLimiter.delete(ip);
    }
  }
}, RATE_WINDOW_MS);

// Validation schemas
const solverEventSchema = z.object({
  id: z.string(),
  assetId: z.string(),
  maintenanceTypeId: z.string(),
  manHours: z.number().positive(),
  earliestPeriod: z.number().int().min(0),
  latestPeriod: z.number().int().min(0),
  targetPeriod: z.number().int().min(0),
  priority: z.number().int().min(1).max(10),
});

const solverInputSchema = z.object({
  events: z.array(solverEventSchema),
  assets: z.array(z.object({
    id: z.string(),
    assetNumber: z.string(),
    assetType: z.string(),
    carsCount: z.number().int().optional(),
    currentMileageKm: z.number(),
    avgDailyMileageKm: z.number(),
    lastMaintenanceDate: z.string().optional(),
    status: z.string().optional(),
    lastMaintenanceKm: z.record(z.string(), z.number()).optional(),
  })),
  maintenanceTypes: z.array(z.object({
    id: z.string(),
    level: z.enum(["A", "B", "C", "D"]),
    name: z.string(),
    description: z.string().optional(),
    intervalKm: z.number().positive(),
    toleranceKm: z.number().positive(),
    durationHours: z.number().positive(),
    manHours: z.number().positive(),
    requiredTracks: z.number().int().positive(),
    estimatedCost: z.number().min(0),
  })),
  constraints: z.object({
    weeklyManHours: z.number().positive(),
    monthlyManHours: z.number().positive(),
    maintenanceTracks: z.number().int().positive(),
    trackCapacityPerDay: z.number().int().positive(),
    depots: z.array(z.object({
      id: z.string(),
      name: z.string(),
      assetTypes: z.array(z.string()),
      trackCount: z.number().int().positive(),
      weeklyManHours: z.number().positive(),
    })),
  }),
  planningHorizonWeeks: z.number().int().positive(),
  objective: z.object({
    peakWorkloadWeight: z.number().optional(),
    levelingWeight: z.number().optional(),
    complianceWeight: z.number().optional(),
  }).optional(),
  settings: z.object({
    timeoutSeconds: z.number().positive().optional(),
    gapTolerance: z.number().min(0).max(1).optional(),
  }).optional(),
});

/**
 * POST /solve - Run the optimization solver
 */
solver.post(
  "/solve",
  zValidator("json", solverInputSchema),
  async (c) => {
    // Rate limiting
    const clientIp = c.req.header("x-forwarded-for") || "unknown";
    if (!checkRateLimit(clientIp)) {
      return c.json(
        {
          status: "ERROR",
          solution: null,
          metrics: null,
          diagnostics: {
            solverName: "HiGHS",
            solveTimeMs: 0,
            iterations: 0,
            warnings: ["Rate limit exceeded. Max 10 requests per minute."],
          },
        },
        429
      );
    }

    const input = c.req.valid("json") as SolverInput;

    try {
      // Create new adapter per request to prevent race conditions
      const adapter = createSolverAdapter();
      const startTime = performance.now();
      const result = await adapter.solve(input);
      const elapsed = performance.now() - startTime;

      return c.json({
        ...result,
        _meta: {
          totalTimeMs: elapsed,
          eventsCount: input.events.length,
          assetsCount: input.assets.length,
        },
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      return c.json(
        {
          status: "ERROR",
          solution: null,
          metrics: null,
          diagnostics: {
            solverName: "HiGHS",
            solveTimeMs: 0,
            iterations: 0,
            warnings: [message],
          },
        },
        500
      );
    }
  }
);

/**
 * GET /health - Health check for solver availability
 */
solver.get("/health", async (c) => {
  try {
    const adapter = createSolverAdapter();
    // Quick test solve with empty input
    const result = await adapter.solve({
      events: [],
      assets: [],
      maintenanceTypes: [],
      constraints: {
        weeklyManHours: 1000,
        monthlyManHours: 4000,
        maintenanceTracks: 1,
        trackCapacityPerDay: 1,
        depots: [],
      },
      planningHorizonWeeks: 1,
    });

    return c.json({
      status: "healthy",
      solver: result.diagnostics.solverName,
      responseTimeMs: result.diagnostics.solveTimeMs,
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    return c.json({ status: "unhealthy", error: message }, 503);
  }
});

export { solver };

