     1→import { useState, useMemo } from "react";
     2→import type { MetaFunction } from "react-router";
     3→import ContentLayout from "@cloudscape-design/components/content-layout";
     4→import Header from "@cloudscape-design/components/header";
     5→import Container from "@cloudscape-design/components/container";
     6→import SpaceBetween from "@cloudscape-design/components/space-between";
     7→import Grid from "@cloudscape-design/components/grid";
     8→import Box from "@cloudscape-design/components/box";
     9→import Button from "@cloudscape-design/components/button";
    10→import ButtonDropdown from "@cloudscape-design/components/button-dropdown";
    11→import Badge from "@cloudscape-design/components/badge";
    12→import Modal from "@cloudscape-design/components/modal";
    13→import Table from "@cloudscape-design/components/table";
    14→import ProgressBar from "@cloudscape-design/components/progress-bar";
    15→import Select from "@cloudscape-design/components/select";
    16→import type { SolverOutput, EventAssignment } from "@uptime/types";
    17→import { generateFleet, generateEvents, maintenanceTypes, TOTAL_FLEET } from "~/lib/demo-data";
    18→
    19→export const meta: MetaFunction = () => {
    20→  return [
    21→    { title: "Maintenance Calendar - Fleet Maintenance" },
    22→    { name: "description", content: "View scheduled maintenance events" },
    23→  ];
    24→};
    25→
    26→// Generate demo schedule data
    27→function generateDemoSchedule(): { assignments: EventAssignment[]; events: Map<string, { assetId: string; maintenanceTypeId: string; manHours: number }> } {
    28→  const assets = generateFleet(TOTAL_FLEET);
    29→  const events = generateEvents(assets, 52);
    30→
    31→  // Create a map for quick event lookup
    32→  const eventMap = new Map(events.map(e => [e.id, { assetId: e.assetId, maintenanceTypeId: e.maintenanceTypeId, manHours: e.manHours }]));
    33→
    34→  // Simulate solver assignments (spread events across periods)
    35→  const assignments: EventAssignment[] = events.map((event, index) => ({
    36→    eventId: event.id,
    37→    assignedPeriod: Math.min(event.latestPeriod, Math.max(event.earliestPeriod, event.targetPeriod + (index % 3) - 1)),
    38→    deviation: 0,
    39→  }));
    40→
    41→  return { assignments, events: eventMap };
    42→}
    43→
    44→// Maintenance type colors
    45→const typeColors: Record<string, string> = {
    46→  "mt-a": "#2ea043", // Green - A-Check
    47→  "mt-b": "#d29922", // Yellow - B-Check
    48→  "mt-c": "#cf222e", // Red - C-Check
    49→  "mt-d": "#8250df", // Purple - D-Overhaul
    50→};
    51→
    52→const typeLabels: Record<string, string> = {
    53→  "mt-a": "A-Check",
    54→  "mt-b": "B-Check",
    55→  "mt-c": "C-Check",
    56→  "mt-d": "D-Overhaul",
    57→};
    58→
    59→interface DayEvents {
    60→  date: Date;
    61→  week: number;
    62→  events: Array<{
    63→    eventId: string;
    64→    assetId: string;
    65→    maintenanceTypeId: string;
    66→    manHours: number;
    67→  }>;
    68→}
    69→
    70→interface WeekData {
    71→  weekNumber: number;
    72→  startDate: Date;
    73→  endDate: Date;
    74→  totalManHours: number;
    75→  eventCount: number;
    76→  events: DayEvents["events"];
    77→}
    78→
    79→export default function Calendar() {
    80→  const [currentMonth, setCurrentMonth] = useState(new Date(2025, 0, 1)); // January 2025
    81→  const [selectedDay, setSelectedDay] = useState<DayEvents | null>(null);
    82→  const [viewMode, setViewMode] = useState<"month" | "week">("month");
    83→  const [filterType, setFilterType] = useState<{ label: string; value: string } | null>(null);
    84→
    85→  // Generate schedule data
    86→  const { assignments, events } = useMemo(() => generateDemoSchedule(), []);
    87→
    88→  // Group events by week
    89→  const eventsByWeek = useMemo(() => {
    90→    const byWeek = new Map<number, DayEvents["events"]>();
    91→
    92→    for (const assignment of assignments) {
    93→      const event = events.get(assignment.eventId);
    94→      if (!event) continue;
    95→
    96→      // Apply filter
    97→      if (filterType && event.maintenanceTypeId !== filterType.value) continue;
    98→
    99→      const week = assignment.assignedPeriod;
   100→      if (!byWeek.has(week)) {
   101→        byWeek.set(week, []);
   102→      }
   103→      byWeek.get(week)!.push({
   104→        eventId: assignment.eventId,
   105→        ...event,
   106→      });
   107→    }
   108→
   109→    return byWeek;
   110→  }, [assignments, events, filterType]);
   111→
   112→  // Get week data for the current view
   113→  const weeksInView = useMemo(() => {
   114→    const weeks: WeekData[] = [];
   115→    const year = currentMonth.getFullYear();
   116→    const month = currentMonth.getMonth();
   117→
   118→    // Get first day of month and find which week it falls in
   119→    const firstDay = new Date(year, month, 1);
   120→    const startWeek = Math.floor((firstDay.getTime() - new Date(year, 0, 1).getTime()) / (7 * 24 * 60 * 60 * 1000));
   121→
   122→    // Get last day of month
   123→    const lastDay = new Date(year, month + 1, 0);
   124→    const endWeek = Math.floor((lastDay.getTime() - new Date(year, 0, 1).getTime()) / (7 * 24 * 60 * 60 * 1000));
   125→
   126→    for (let w = startWeek; w <= endWeek && w < 52; w++) {
   127→      const weekEvents = eventsByWeek.get(w) || [];
   128→      const startDate = new Date(year, 0, 1 + w * 7);
   129→      const endDate = new Date(year, 0, 7 + w * 7);
   130→
   131→      weeks.push({
   132→        weekNumber: w + 1,
   133→        startDate,
   134→        endDate,
   135→        totalManHours: weekEvents.reduce((sum, e) => sum + e.manHours, 0),
   136→        eventCount: weekEvents.length,
   137→        events: weekEvents,
   138→      });
   139→    }
   140→
   141→    return weeks;
   142→  }, [currentMonth, eventsByWeek]);
   143→
   144→  // Calculate capacity utilization
   145→  const weeklyCapacity = 5200;
   146→
   147→  // Navigation handlers
   148→  const previousMonth = () => {
   149→    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1));
   150→  };
   151→
   152→  const nextMonth = () => {
   153→    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1));
   154→  };
   155→
   156→  const monthName = currentMonth.toLocaleDateString("en-US", { month: "long", year: "numeric" });
   157→
   158→  // Count events by type for legend
   159→  const eventCounts = useMemo(() => {
   160→    const counts: Record<string, number> = { "mt-a": 0, "mt-b": 0, "mt-c": 0, "mt-d": 0 };
   161→    for (const week of weeksInView) {
   162→      for (const event of week.events) {
   163→        counts[event.maintenanceTypeId] = (counts[event.maintenanceTypeId] || 0) + 1;
   164→      }
   165→    }
   166→    return counts;
   167→  }, [weeksInView]);
   168→
   169→  return (
   170→    <ContentLayout
   171→      header={
   172→        <Header
   173→          variant="h1"
   174→          description="View and validate scheduled maintenance events"
   175→          actions={
   176→            <SpaceBetween direction="horizontal" size="xs">
   177→              <Select
   178→                selectedOption={filterType}
   179→                onChange={({ detail }) => setFilterType(detail.selectedOption as { label: string; value: string } | null)}
   180→                options={[
   181→                  { label: "All Types", value: "" },
   182→                  { label: "A-Check", value: "mt-a" },
   183→                  { label: "B-Check", value: "mt-b" },
   184→                  { label: "C-Check", value: "mt-c" },
   185→                  { label: "D-Overhaul", value: "mt-d" },
   186→                ]}
   187→                placeholder="Filter by type"
   188→              />
   189→              <ButtonDropdown
   190→                items={[
   191→                  { text: "Export to Excel", id: "excel" },
   192→                  { text: "Export to PDF", id: "pdf" },
   193→                  { text: "Export for Maximo", id: "maximo" },
   194→                ]}
   195→              >
   196→                Export
   197→              </ButtonDropdown>
   198→            </SpaceBetween>
   199→          }
   200→        >
   201→          Maintenance Calendar
   202→        </Header>
   203→      }
   204→    >
   205→      <SpaceBetween size="l">
   206→        {/* Legend */}
   207→        <Container>
   208→          <SpaceBetween direction="horizontal" size="l">
   209→            <Box variant="span" fontWeight="bold">Legend:</Box>
   210→            {Object.entries(typeLabels).map(([id, label]) => (
   211→              <SpaceBetween key={id} direction="horizontal" size="xxs">
   212→                <div style={{
   213→                  width: 16,
   214→                  height: 16,
   215→                  backgroundColor: typeColors[id],
   216→                  borderRadius: 4,
   217→                  display: "inline-block",
   218→                }} />
   219→                <Box variant="span">{label}</Box>
   220→                <Badge color="blue">{eventCounts[id]}</Badge>
   221→              </SpaceBetween>
   222→            ))}
   223→          </SpaceBetween>
   224→        </Container>
   225→
   226→        {/* Calendar Navigation */}
   227→        <Container
   228→          header={
   229→            <Header
   230→              variant="h2"
   231→              actions={
   232→                <SpaceBetween direction="horizontal" size="xs">
   233→                  <Button iconName="angle-left" variant="icon" onClick={previousMonth} />
   234→                  <Box variant="h3" padding={{ horizontal: "l" }}>{monthName}</Box>
   235→                  <Button iconName="angle-right" variant="icon" onClick={nextMonth} />
   236→                </SpaceBetween>
   237→              }
   238→            >
   239→              Weekly Schedule
   240→            </Header>
   241→          }
   242→        >
