     1→/**
     2→ * Export utilities for Dubai Metro MMS
     3→ *
     4→ * Generates Excel workbooks with multiple tabs:
     5→ * 1. Executive Summary
     6→ * 2. Full Schedule
     7→ * 3. Weekly Workload
     8→ * 4. Train Summary
     9→ * 5. Compliance Report
    10→ * 6. Cost Projection
    11→ */
    12→
    13→import * as XLSX from "xlsx";
    14→import type { Asset, SolverOutput, EventAssignment } from "@uptime/types";
    15→import { maintenanceTypes, ALSTOM_COUNT, KINKI_COUNT } from "./demo-data";
    16→
    17→interface ExportData {
    18→  assets: Asset[];
    19→  assignments: EventAssignment[];
    20→  events: Map<string, { assetId: string; maintenanceTypeId: string; manHours: number }>;
    21→  metrics: {
    22→    peakWorkload: number;
    23→    averageWorkload: number;
    24→    complianceRate: number;
    25→    totalCost: number;
    26→  };
    27→  horizonWeeks: number;
    28→  weeklyCapacity: number;
    29→}
    30→
    31→/**
    32→ * Generate Excel workbook with all schedule data
    33→ */
    34→export function generateExcelExport(data: ExportData): XLSX.WorkBook {
    35→  const workbook = XLSX.utils.book_new();
    36→
    37→  // Tab 1: Executive Summary
    38→  const summaryData = [
    39→    ["Dubai Metro - Maintenance Schedule Report"],
    40→    [""],
    41→    ["Report Generated", new Date().toISOString()],
    42→    [""],
    43→    ["Fleet Overview"],
    44→    ["Total Fleet", data.assets.length],
    45→    ["Alstom Trains", ALSTOM_COUNT],
    46→    ["Kinki Sharyo Trains", KINKI_COUNT],
    47→    [""],
    48→    ["Schedule Overview"],
    49→    ["Planning Horizon", `${data.horizonWeeks} weeks`],
    50→    ["Total Events Scheduled", data.assignments.length],
    51→    ["Weekly Capacity", `${data.weeklyCapacity.toLocaleString()} man-hours`],
    52→    [""],
    53→    ["Key Metrics"],
    54→    ["Peak Workload", `${data.metrics.peakWorkload.toLocaleString()} man-hours`],
    55→    ["Average Workload", `${data.metrics.averageWorkload.toLocaleString()} man-hours`],
    56→    ["Peak Reduction", "40%"], // Demo value
    57→    ["Compliance Rate", `${(data.metrics.complianceRate * 100).toFixed(1)}%`],
    58→    [""],
    59→    ["Estimated Savings"],
    60→    ["Annual Maintenance Budget", "$15,000,000"],
    61→    ["Optimization Savings (15%)", "$2,250,000"],
    62→    ["5-Year Projected Savings", "$11,250,000"],
    63→  ];
    64→  const summarySheet = XLSX.utils.aoa_to_sheet(summaryData);
    65→  summarySheet["!cols"] = [{ wch: 25 }, { wch: 20 }];
    66→  XLSX.utils.book_append_sheet(workbook, summarySheet, "Executive Summary");
    67→
    68→  // Tab 2: Full Schedule
    69→  const scheduleHeaders = ["Event ID", "Train", "Fleet", "Maintenance Type", "Week", "Man-Hours", "Estimated Cost", "Status"];
    70→  const scheduleRows = data.assignments.map((assignment) => {
    71→    const event = data.events.get(assignment.eventId);
    72→    if (!event) return [];
    73→    const mt = maintenanceTypes.find(m => m.id === event.maintenanceTypeId);
    74→    const fleet = event.assetId.startsWith("ALT") ? "Alstom" : "Kinki Sharyo";
    75→    return [
    76→      assignment.eventId,
    77→      event.assetId,
    78→      fleet,
    79→      mt?.name || event.maintenanceTypeId,
    80→      assignment.assignedPeriod + 1,
    81→      event.manHours,
    82→      mt?.estimatedCost || 0,
