import { Menu, MenuItem, MenuDivider, Icon } from "@blueprintjs/core";

interface SidebarProps {
  currentPath: string;
}

const navItems = [
  { href: "/", icon: "dashboard", text: "Dashboard" },
  { href: "/fleet", icon: "train", text: "Fleet" },
  { href: "/schedule", icon: "calendar", text: "Schedule" },
  { href: "/calendar", icon: "timeline-events", text: "Calendar" },
  { type: "divider" as const },
  { href: "/what-if", icon: "lab-test", text: "What-If Simulator" },
];

export function Sidebar({ currentPath }: SidebarProps) {
  return (
    <div className="sidebar">
      <div style={{ padding: "20px 16px", borderBottom: "1px solid #394b59" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
          <Icon icon="train" size={24} color="#48aff0" />
          <div>
            <div style={{ fontWeight: 600, fontSize: "16px" }}>MMS</div>
            <div style={{ fontSize: "11px", color: "#a7b6c2" }}>Dubai Metro</div>
          </div>
        </div>
      </div>
      <Menu large style={{ background: "transparent", padding: "8px" }}>
        {navItems.map((item, index) => {
          if (item.type === "divider") {
            return <MenuDivider key={index} />;
          }
          const isActive = currentPath === item.href;
          return (
            <MenuItem
              key={item.href}
              icon={item.icon as any}
              text={item.text}
              href={item.href}
              active={isActive}
              style={{
                borderRadius: "6px",
                marginBottom: "4px",
                color: isActive ? "#48aff0" : "#bfccd6",
