import { HTMLTable, Tag, Intent } from "@blueprintjs/core";
import { generateFleet, generateEvents, maintenanceTypes, TOTAL_FLEET } from "../lib/demo-data";
import { useMemo } from "react";

const typeColors: Record<string, Intent> = {
  "mt-a": Intent.SUCCESS,
  "mt-b": Intent.WARNING,
  "mt-c": Intent.DANGER,
  "mt-d": Intent.PRIMARY,
};

export function ScheduleTable() {
  const events = useMemo(() => {
    const fleet = generateFleet(TOTAL_FLEET);
    return generateEvents(fleet, 52);
  }, []);

  const getMaintenanceType = (id: string) => {
    return maintenanceTypes.find((mt) => mt.id === id);
  };

  return (
    <div style={{ overflowX: "auto" }}>
      <p style={{ color: "#5f6b7c", marginBottom: "16px" }}>
        Showing {events.length} maintenance events for the next 52 weeks
      </p>
      <HTMLTable striped interactive style={{ width: "100%" }}>
        <thead>
          <tr>
            <th>Event ID</th>
            <th>Train</th>
            <th>Type</th>
            <th>Target Week</th>
            <th>Window</th>
            <th>Man-Hours</th>
          </tr>
        </thead>
        <tbody>
          {events.slice(0, 100).map((event) => {
            const mt = getMaintenanceType(event.maintenanceTypeId);
            return (
              <tr key={event.id}>
                <td><code>{event.id}</code></td>
                <td><strong>{event.assetId}</strong></td>
                <td>
                  <Tag intent={typeColors[event.maintenanceTypeId]}>
                    {mt?.name || event.maintenanceTypeId}
                  </Tag>
                </td>
                <td>Week {event.targetPeriod + 1}</td>
                <td>
                  Week {event.earliestPeriod + 1} - {event.latestPeriod + 1}
                </td>
                <td>{event.manHours}h</td>
              </tr>
            );
          })}
        </tbody>
      </HTMLTable>
      {events.length > 100 && (
        <p style={{ color: "#5f6b7c", marginTop: "16px" }}>
          Showing first 100 of {events.length} events
        </p>
      )}
    </div>
  );
}

