// @ts-check
import { defineConfig } from 'astro/config';
import react from '@astrojs/react';

// https://astro.build/config
export default defineConfig({
  integrations: [react()],
  server: {
    port: 3000,
  },
  vite: {
    ssr: {
      noExternal: [
        '@blueprintjs/core',
        '@blueprintjs/icons',
        '@blueprintjs/select',
        '@blueprintjs/table',
        '@blueprintjs/datetime',
        '@popperjs/core',
      ],
    },
    optimizeDeps: {
      include: ['@blueprintjs/core', '@blueprintjs/icons', '@popperjs/core'],
    },
  },
});
